import type MapSurroundInfoGroupElement from "./MapSurroundInfoGroupElement.js";
import type MapSurroundInfoLegend from "./MapSurroundInfoLegend.js";
import type MapSurroundInfoNorthArrow from "./MapSurroundInfoNorthArrow.js";
import type MapSurroundInfoScaleLine from "./MapSurroundInfoScaleLine.js";
import type { PrintLayoutTemplate, PrintFileFormat, LengthUnit } from "../../rest/support/types.js";

/** @since 5.0 */
export interface TemplateInfo<ValueType> {
  /**
   * A list of supported layouts.
   *
   * @since 5.0
   */
  choiceList: ValueType[];
  /**
   * The default layout selected by the print service.
   *
   * @since 5.0
   */
  defaultValue: ValueType;
}

/** @since 5.0 */
export interface TemplatesInfo {
  /**
   * Metadata about the available output formats.
   *
   * @since 5.0
   */
  format: TemplateInfo<PrintFileFormat>;
  /**
   * Metadata about the available page layouts.
   *
   * @since 5.0
   */
  layout: TemplateInfo<PrintLayoutTemplate>;
}

/** @since 5.0 */
export type Layout = string;

/** @since 5.0 */
export type Layouts = "all" | Layout[];

/** @since 5.0 */
export type Format = string;

/** @since 5.0 */
export type Formats = "all" | Format[];

/** @since 5.0 */
export type State = "ready" | "initializing" | "disabled" | "error";

/** @since 5.0 */
export type CustomTextElement = Record<string, string>;

/** @since 5.0 */
export type TemplateCustomTextElements = Record<string, CustomTextElement[]>;

/** @since 5.0 */
export type MapSurroundInfoType = "cim-marker-north-arrow" | "cim-scale-line" | "cim-legend" | "cim-group-element";

/** @since 5.0 */
export type ScaleBarUnit = Extract<LengthUnit, "meters" | "feet" | "nautical-miles" | "kilometers" | "miles" | "yards">;

/** @since 5.0 */
export interface MapSurroundInfoLegendItem {
  /** @since 5.0 */
  dynamicLegends: boolean;
}

/** @since 5.0 */
export type MapSurroundInfo = MapSurroundInfoNorthArrow | MapSurroundInfoScaleLine | MapSurroundInfoLegend | MapSurroundInfoGroupElement;